INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('judgment', '党的纪律处分工作应遵循党纪面前一律平等的原则，对违犯 党纪的党组织和党员必须严肃、公正执行纪律，党内不允许有任 何不受纪律约束的党组织和党员。', 'Y', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('judgment', '党员行为虽然造成损失或者后果，但不是出于故意或者过失， 而是由于不可抗力等原因所引起的，不追究党纪责任。', 'Y', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('judgment', '党员因违犯党纪受到处分，影响期满后，党组织无需取消对 其的处分。', 'Y', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('judgment', '从轻处分，是指在《中国共产党纪律处分条例》规定的违纪 行为应当受到的处分幅度以内，减轻一档给予处分。', 'N', NULL, '', NOW(), NOW());
