INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('judgment', '党员领导干部不重视家风建设，对配偶、子女及其配偶失管 失教，情节严重的，给予开除党籍处分。', 'N', NULL, '', NOW(), NOW());
