INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('judgment', '《党章》规定，党组织必须严格执行和维护党的纪律，共产 党员必须自觉接受党的纪律的约束。', 'Y', NULL, '', NOW(), NOW());
