INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('judgment', '《党章》规定，党员个人代表党组织发表重要主张，如果超 出党组织已有决定的范围，只能提交上级党组织决定。', 'N', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('judgment', '《党章》规定，党员必须维护党的团结和统一，对党忠诚老 实，言行一致，坚决反对一切派别组织和小集团活动，反对阳奉 阴违的两面派行为和一切阴谋诡计。', 'Y', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('judgment', '《党章》规定，民主集中制是民主基础上的集中和集中指导 下的民主相结合。', 'Y', NULL, '', NOW(), NOW());
