INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('judgment', '新时代新征程，经济和社会发展的战略目标是，到二〇三五 年基本实现社会主义现代化，到本世纪中叶把我国建成社会主义 现代化强国。', 'Y', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('judgment', '新的征程上，我们必须坚持党的基本理论、基本路线、基本 方略，统筹推进“五位一体”总体布局、协调推进“四个全面” 战略布局。', 'Y', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('judgment', '江山就是人民，人民就是江山，打江山、守江山，守的是人 民的心。中国共产党根基在人民、血脉在人民、力量在人民。中 国共产党始终代表最广大人民根本利益，与人民休戚与共、生死 — 18 — 相依，没有任何自己特殊的利益，从来不代表任何利益集团、任 何权势团体、任何特权阶层的利益。', 'Y', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('judgment', '英雄人物是历史的创造者，是真正的英雄。', 'N', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('judgment', '人民性是马克思主义的根本属性，是它最鲜明的品格。我们 党是用马克思主义武装起来的政党，人民性也是我们党的根本属 性。', 'Y', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('judgment', '以史为鉴、开创未来，必须做到4 个“必须”。', 'N', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('judgment', '中国共产党第二十次全国代表大会的主题是高举中国特色 社会主义伟大旗帜，全面贯彻新时代中国特色社会主义思想，弘 扬伟大建党精神，自信自强、守正创新，踔厉奋发、勇毅前行， 为全面建设社会主义现代化国家、全面推进中华民族伟大复兴而 团结奋斗。', 'Y', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('judgment', '习近平在党的二十大报告中指出，党的十八大以来的十年， 我们党团结带领人民，攻克了许多长期没有解决的难题，办成了 许多事关长远的大事要事，推动党和国家事业取得彪炳史册的历 史胜利。', 'N', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('judgment', '坚持社会主义道路、坚持人民民主专政、坚持中国共产党的 领导、坚持马列主义、毛泽东思想这四项基本原则，是我们的立 国之本。', 'Y', NULL, '', NOW(), NOW());
