INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('judgment', '党的二十大报告提出，坚持把发展经济的着力点放在实体经 济上，推进新型工业化，加快建设制造强国、质量强国、航天强 国、交通强国、网络强国、数字中国。', 'Y', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('judgment', '党的十八大报告深化了对中国特色社会主义的认识，首次将 “中国特色社会主义制度”写入党的全国代表大会报告中。', 'Y', NULL, '', NOW(), NOW());
