INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '把（全面建成社会主义现代化强国，分两步走）的总的战略 安排写入党章，即：到二〇三五年基本实现社会主义现代化， 到本世纪中叶把我国建成社会主义现代化强国。这凝聚起全 党全国各族人民共同奋斗的意志和力量，激励着全党全国人 民坚定信心、锐意进取。', '', NULL, '', NOW(), NOW());
