INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '党章规定，中国共产党代表中国先进生产力的发展要求，代 表中国先进文化的前进方向，代表（中国最广大人民的根本 利益）。', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '二十届三中全会指出，进一步全面深化改革的总目标是继续 完善和发展（中国特色社会主义制度），推进国家治理体系 和治理能力现代化。', '', NULL, '', NOW(), NOW());
