INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '党的二十届四中全会指出，“十五五”时期经济社会发展以 （满足人民日益增长的美好生活需要）为根本目的。', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '习近平新时代中国特色社会主义思想是党和人民实践经验 和集体智慧的结晶，是（中国特色社会主义理论体系）的重 要组成部分。', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '党的二十届四中全会强调，要坚持（有效市场）和有为政府 相结合，推动经济社会高质量发展。', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '党章规定，党的最大政治优势是（密切联系群众），党执政 后的最大危险是脱离群众。', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '党的二十届四中全会提出，要坚决破除阻碍（全国统一大市 场）建设卡点堵点，增强国内大循环内生动力。', '', NULL, '', NOW(), NOW());
