INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '党的二十届四中全会指出，要如期实现（建军一百年）奋斗 目标，高质量推进国防和军队现代化。', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '（新质生产力）是生产力中创新最活跃、技术最前沿、前景 最广阔、影响最广泛的部分，代表生产力的演进方向。', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '“十五五”时期国防和军队现代化建设，一定要把（政治建 军）摆在首要位置。', '', NULL, '', NOW(), NOW());
