INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '（防灾减灾救灾）涉及经济、社会、生态等各个领域，既是 国家治理的首要任务，又是国家治理能力的重要体现。', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '新时代以来，以习近平同志为核心的党中央高度重视（平安 中国建设），领导广大人民群众成功续写了经济快速发展和 社会长期稳定两大奇迹新篇章。', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '衡量党性强弱的根本尺子是（公）、（私）二字。只有党性 坚强、摒弃私心杂念，才能保证政绩观不出偏差。', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '各级领导干部要树立和践行正确政绩观，以（功成不必在我、 功成必定有我)的精神境界，心无旁骛推进中国式现代化。', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '《党章》明确，必须按照中国特色社会主义事业“（五位一 体）”总体布局和“（四个全面）”战略布局，全面统筹推 进经济建设、政治建设、文化建设、社会建设、生态文明建 设，协调推进全面建成小康社会、全面深化改革、全面依法 治国、全面从严治党。', '', NULL, '', NOW(), NOW());
