INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '（《中国共产党的第一个纲领》）是党的第一个正式文献， 虽然不是正式的党章，实际上起到了党章的作用。', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '中国进入改革开放和社会主义现代化建设新时期的起点是 （党的十一届三中全会）的召开。', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '党性、党风、党纪是有机整体，（党性）是根本，（党风） 是表现，（党纪）是保障。', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '党支部召开党员大会开展民主评议党员时，按照（个人自评）、 （党员互评）、（民主测评）的程序，组织党员进行评议。', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '党的基层组织进行选举时，有选举权的到会人数不少于应到 会人数的（五分之四），会议有效。', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '中国梦的本质是（国家富强）、（民族振兴）、（人民幸福）。', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '中国共产党的象征和标志是（党徽）和（党旗）。', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '（文化）认同是最深层次的认同，是民族团结之根、民族和 睦之魂。', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '习近平总书记在2023年中央经济工作会议中指出，必须把推 进（中国式现代化）作为最大的政治。', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('fill_blank', '保证全党服从中央，坚持党中央权威和集中统一领导是党的 （政治建设）的首要任务。', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '中国共产党的性质是什么？', '中国共产党是中国工人阶级的先锋队，同时是中国人民和中 华民族的先锋队，是中国特色社会主义事业的领导核心，代表中 国先进生产力的发展要求，代表中国先进文化的前进方向，代表 中国最广大人民的根本利益。党的最高理想和最终目标是实现共 产主义。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '中国共产党的指导思想是什么？', '中国共产党以马克思列宁主义、毛泽东思想、邓小平理论、 “三个代表”重要思想、科学发展观、习近平新时代中国特色社 会主义思想作为自己的行动指南。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '共产党员必须履行的八项义务是什么？', '根据党章第三条的规定，党员必须履行下列义务： （一）认真学习马克思列宁主义、毛泽东思想、邓小平理论、“三 个代表”重要思想、科学发展观、习近平新时代中国特色社会主 义思想，学习党的路线、方针、政策和决议，学习党的基本知识 和党的历史，学习科学、文化、法律和业务知识，努力提高为人 民服务的本领。 （二）增强“四个意识”、坚定“四个自信”、做到“两个维护”， 贯彻执行党的基本路线和各项方针、政策，带头参加改革开放和 社会主义现代化建设，带动群众为经济发展和社会进步艰苦奋斗， 在生产、工作、学习和社会生活中起先锋模范作用。 （三）坚持党和人民的利益高于一切，个人利益服从党和人民的 利益，吃苦在前，享受在后，克己奉公，多做贡献。 （四）自觉遵守党的纪律，首先是党的政治纪律和政治规矩，模 范遵守国家的法律法规，严格保守党和国家的秘密，执行党的决 定，服从组织分配，积极完成党的任务。 （五）维护党的团结和统一，对党忠诚老实，言行一致，坚决反 对一切派别组织和小集团活动，反对阳奉阴违的两面派行为和一 切阴谋诡计。 （六）切实开展批评和自我批评，勇于揭露和纠正违反党的原则 的言行和工作中的缺点、错误，坚决同消极腐败现象作斗争。 （七）密切联系群众，向群众宣传党的主张，遇事同群众商量， 及时向党反映群众的意见和要求，维护群众的正当利益。 （八）发扬社会主义新风尚，带头实践社会主义核心价值观和社 会主义荣辱观，提倡共产主义道德，弘扬中华民族传统美德，为 了保护国家和人民的利益，在一切困难和危险的时刻挺身而出， 英勇斗争，不怕牺牲', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '中国共产党的根本宗旨是什么？', '全心全意为人民服务是党的根本宗旨。党除了工人阶级和最 广大人民群众的利益，没有自己特殊的利益。党在任何时候都把 群众利益放在第一位，同群众同甘共苦，保持最密切的联系。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '2021 年1 月4 日，新修订的《中国共产党党员权利保障条例》 全文公布。修订后的条例用13 个条文将党章规定的8 个方面 党员权利进一步明确细化。党员的13 项权利都有哪些？ （1）党内知情权 （2）接受党的教育培训权 （3）党内参加讨论权 （4）党内建议和倡议权 （5）党内监督权 （6）党内提出罢免撤换要求权 （7）党内表决权 （8）党内选举权和被选举权 （9）党内申辩权 （10）党内提出不同意见权 （11）党内请求权 （12）党内申诉权 （13）党内控告权', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '中国共产党的入党誓词是什么?', '我志愿加入中国共产党，拥护党的纲领，遵守党的章程，履 行党员义务，执行党的决定，严守党的纪律，保守党的秘密，对 党忠诚，积极工作，为共产主义奋斗终身，随时准备为党和人民 牺牲一切，永不叛党。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '预备党员享有哪些权利？', '预备党员的义务同正式党员一样。预备党员的权利，除了没 有表决权、选举权和被选举权以外，也同正式党员一样。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '“五位一体”总体布局指的是什么？', '“五位一体”总体布局是指经济建设、政治建设、文化建设、 社会建设和生态文明建设五位一体，全面推进。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '为什么要端正入党动机？正确的入党动机是怎样形成的？', '正确的入党动机是思想上入党的根本问题，是激励人们入党 的主观原因，它从根本上决定了每一个党员的素质和行为，是共 产党员的世界观、人生观的集中反映。因此，树立正确的入党动 机是十分重要的问题。正确的入党动机，指争取入党的内在原因 是忠诚地信仰共产主义，把最终实现共产主义社会制度作为自己 的最高理想，决心为了壮丽的共产主义事业奋斗终身，全心全意 为人民服务。 (1)要求入党的同志因为他们受到党的培养教育，使人生道路上 锻炼成长，在事业上取得一定的成绩，使他们对党产生朴素的热 爱之情。 (2)作为知识分子要认识和理解党的基本知识，基本纲领，基本 路线，基本经验，认真学习党的基本知识，了解党的性质，党的 指导思想，党的基本宗旨，党的奋斗目标，党的基本原则等，培 养理性认识在积极分子入党动机的提升上起着至关重要的作用。 (3)入党积极分子只有将理论和实践紧密结合起来，才能逐步实 现既定的远大目标。 （4）通过反复的实践，将积极分子的思想认识和政治觉悟提高 到一个新的境界，最终树立起坚定的共产主义信仰。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '为什么说端正入党动机是要求入党的同志必须解决的首要问 题?', '(1)入党动机正确与否，不仅关系到要求入党的同志能否为 创造入党条件产生正确的导向和内在动力，而且关系到要求入党 的同志能否在入党以后始终不渝地坚持共产党人的世界观、人生 观、价值观，永葆共产党员的本色。 (2)正确的入党动机可以产生正确的入党行为，并用科学的方法 去实践它；不正确的入党动机则会驱使人们采用不正确的思想和 行为去实现个人的愿望。所以，端正入党动机是要求入党的同志 必须解决的首要问题。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '国际歌歌词内容', '第一段：起来饥寒交迫的奴隶，起来全世界受苦的人，满腔 的热血已经沸腾，要为真理而斗争。旧世界打个落花流水，奴隶 们起来、起来！不要说我们一无所有，我们要做天下的主人。这 是最后的斗争，团结起来到明天，英特纳雄耐尔就一定要实现！ 这是最后的斗争，团结起来到明天，英特纳雄耐尔就一定要实现！ （第二段和第三段略）。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '马克思主义经典作家把从资本主义到共产主义划分为哪三个 阶段？', '马克思主义经典作家把从资本主义到共产主义划分为三个阶 段：一是从资本主义到共产主义的过渡时期；二是共产主义的低 级阶段即社会主义社会；三是共产主义的高级阶段即共产主义社 会。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '党的纪律主要包括哪六大类？', '政治纪律、组织纪律、廉洁纪律、群众纪律、工作纪律、生 活纪律。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '对党员的纪律处分有哪五种？', '警告、严重警告、撤销党内职务、留党察看、开除党籍。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '社会主义核心价值观的内容是什么？', '国家层面：富强、民主、文明、和谐；社会层面：自由、平 等、公正、法治；个人层面：爱国、敬业、诚信、友善。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '习近平总书记指出，中国共产党的先驱们创建了中国共产党， 形成了怎样的伟大建党精神？', '形成了坚持真理、坚守理想，践行初心、担当使命，不怕牺 牲、英勇斗争，对党忠诚、不负人民的伟大建党精神。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '我们经历了对党和人民事业具有重大现实意义和深远历史意 义的三件大事，这三件大事是什么？', '一是迎来中国共产党成立一百周年，二是中国特色社会主义 进入新时代，三是完成脱贫攻坚、全面建成小康社会的历史任务， 实现第一个百年奋斗目标。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '中国共产党第二十次全国代表大会的主题是什么？', '高举中国特色社会主义伟大旗帜，全面贯彻新时代中国特色 社会主义思想，弘扬伟大建党精神，自信自强、守正创新，踔厉 奋发、勇毅前行，为全面建设社会主义现代化国家、全面推进中 华民族伟大复兴而团结奋斗。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '“六个必须坚持”就是习近平新时代中国特色社会主义思想 的世界观和方法论的集中反映，是逻辑缜密的理论体系，请 问这“六个坚持”是什么？', '必须坚持人民至上，必须坚持自信自立，必须坚持守正创新， 必须坚持问题导向，必须坚持系统观念，必须坚持胸怀天下。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '根据新修订《中国共产党纪律处分条例》规定，党的纪律处 分工作遵循哪些原则？', '坚持党要管党、全面从严治党。党纪面前一律平等。实事求 是。民主集中制。惩前毖后、治病救人。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '简述规定党员义务和权利的必要性。', '第一，规定党员的义务和权利是保证党的先进性、提高党的 战斗力和实现党的正确领导的需要。规定了党员的义务就是规定 了共产党员的具体标准。规定了党员的权利，有利于调动党员的 积极性和创造性，更好地完成党的历史使命，巩固党的执政地位 和提高党的执政能力。 第二，规定党员的义务和权利，是加强党同人民群众联系、保证 中国特色社会主义事业顺利进行的需要。 第三，规定党员的义务和权利，是推动社会主义民主建设和坚持 民主集中制原则的需要。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '简述“十五五”时期经济社会发展必须遵循的原则', '（1）关于坚持党的全面领导； （2）关于坚持人民至上； （3）关于坚持高质量发展； （4）关于坚持全面深化改革； （5）关于坚持有效市场和有为政府相结合； （6）关于坚持统筹发展和安全', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '《建议》提出的“十五五”时期经济社会发展的主要目标是 什么？', '（1）全面建设社会主义现代化国家新征程实现良好开局， 为向新的目标迈进提供了坚实基础； （2）锚定到2035 年我国发展的总体目标，科学制定阶段性目标 任务； （3）紧紧抓住战略机遇，在危机中育新机、于变局中开新局', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '党的二十届四中全会提出的提高党对进一步全面深化改革、 推进中国式现代化领导水平的主要要求有哪些？', '（1）坚持党中央对进一步全面深化改革的集中统一领导 （2）深化党的建设制度改革 （3）坚持党的自我革命 （4）以钉钉子精神抓好改革落实 （5）持续以党的理论统一思想，统一意志，统一行动', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '根据党的二十大报告，新时期应如何开辟马克思主义中国化 时代化新境界？', '坚持和发展马克思主义，必须同中国具体实际相结合；坚持 和发展马克思主义，必须同中华优秀传统文化相结合。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '简述“两个确立”的决定性意义。', '“两个确立”是新时代取得一切成就最根本的保证，是党应 对一切不确定性的最大确定性、最大底气、最大保证；深刻领悟 “两个确立”的决定性意义，才能增强“四个意识”、坚定“四 个自信”、做到“两个维护”，凝聚起推进中国式现代化的磅礴 力量。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '中国共产党在社会主义初级阶段的基本路线是什么？', '中国共产党在社会主义初级阶段的基本路线是：领导和团结 全国各族人民，以经济建设为中心，坚持四项基本原则、坚持改 革开放，自力更生，艰苦创业，为把我国建设成为富强、民主、 文明、和谐、美丽的社会主义现代化强国而奋斗。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '四项基本原则的内容是什么？', '四项基本原则是指坚持社会主义道路、坚持人民民主专政、 坚持中国共产党的领导、坚持马克思列宁主义毛泽东思想这四项 基本原则，是我们的立国之本。在社会主义现代化建设的整个过 程中，必须坚持四项基本原则，反对资产阶级自由化。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '“四个意识”和“两个维护”的内容分别是什么？', '“四个意识”是政治意识、大局意识、核心意识、看齐意识。 “两个维护”是指坚决维护习近平总书记党中央的核心、全党的 核心地位，坚决维护党中央权威和集中统一领导。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '简述中国式现代化的五个中国特色。', '人口规模巨大的现代化、全体人民共同富裕的现代化、物质 文明和精神文明相协调的现代化、人与自然和谐共生的现代化、 走和平发展道路的现代化。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '新时代我国社会的主要矛盾是什么？', '新时代我国社会的主要矛盾是人民日益增长的美好生活需要 和不平衡不充分的发展之间的矛盾。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '简述中国式现代化的本质要求。', '坚持中国共产党领导，坚持中国特色社会主义，实现高质量 发展，发展全过程人民民主，丰富人民精神世界，实现全体人民 共同富裕，促进人与自然和谐共生，推动构建人类命运共同体， 创造人类文明新形态。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '党员发展工作的十六字方针是什么？', '控制总量、优化结构、提高质量、发挥作用。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '入党的基本条件是什么？', '年满十八岁的中国工人、农民、军人、知识分子和其他社会 阶层的先进分子，承认党的纲领和章程，愿意参加党的一个组织 并在其中积极工作、执行党的决议和按期交纳党费的，可以申请 加入中国共产党。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '什么是党的纲领？分为哪两个层面？', '党的纲领是党的政治主张和奋斗目标的集中体现，是党团结 带领人民前进的旗帜。分为最高纲领和最低纲领，最高纲领是实 现共产主义，最低纲领是结合不同历史阶段的国情制定的阶段性 奋斗目标。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '党的三大历史任务是什么？', '推进现代化建设、完成祖国统一、维护世界和平与促进共同 发展。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '新时代党的建设总要求是什么？', '坚持和加强党的全面领导，坚持党要管党、全面从严治党， 以加强党的长期执政能力建设、先进性和纯洁性建设为主线，以 党的政治建设为统领，以坚定理想信念宗旨为根基，以调动全党 积极性、主动性、创造性为着力点，全面推进党的政治建设、思 想建设、组织建设、作风建设、纪律建设，把制度建设贯穿其中， 深入推进反腐败斗争，不断提高党的建设质量。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '党章规定的党的建设必须坚决实现的基本要求有哪些？', '（1）坚持党的基本路线； （2）坚持解放思想，实事求是，与时俱进，求真务实； （3）坚持全心全意为人民服务； （4）坚持民主集中制。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '简述二十届三中全会提出的“六个坚持”重大原则的核心要 义。', '（1）坚持党的全面领导 （2）坚持以人民为中心 （3）坚持守正创新 （4）坚持以制度建设为主线 （5）坚持全面依法治国 （6）坚持系统观念', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '党的二十届四中全会提出的建设现代化产业体系的重点方向 是什么？', '坚持把发展经济的着力点放在实体经济上，坚持智能化、绿 色化、融合化方向，加快建设制造强国、质量强国、航天强国、 交通强国、网络强国；保持制造业合理比重，优化提升传统产业， 培育壮大新兴产业和未来产业，促进服务业优质高效发展，构建 现代化基础设施体系。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '依法治国的总目标是什么？', '建设中国特色社会主义法治体系，建设社会主义法治国家。', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '简述正确政绩观的核心内涵。', '（1）政绩观问题是一个根本性问题，关乎立党为公、执政为民 （2）树立和践行正确政绩观，起决定性作用的是党性 （3）为民造福是最大政绩，坚持以人民为中心 （4）高质量发展是全面建设社会主义现代化国家的首要任务 （5）追求经得起实践、人民、历史检验的实绩', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('short_answer', '简述树立和践行正确政绩观学习教育的总要求', '立党为公、为民造福、科学决策、真抓实干', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('essay', '中国共产党的最终目标是什么？联系实际谈谈自己的认识？', '', NULL, '', NOW(), NOW());
