INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('essay', '正确的入党动机是什么？结合新党章的有关要求联系实际，谈 谈自己怎样以实际行动争取早日加入党组织？', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('essay', '谈谈如何按照党员标准严格要求自己，切实发挥先锋模范作用， 以实际行动做一名“四讲四有”的合格共产党员？', '', NULL, '', NOW(), NOW());
