INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('essay', '结合党的二十届四中全会精神和党的二十大党章要求，谈谈 新时代入党发展对象应如何坚定理想信念、践行初心使命。', '', NULL, '', NOW(), NOW());
