INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('essay', '谈谈你对中国特色社会主义道路的理解，以及新时代青年如 何坚定道路自信。', '', NULL, '', NOW(), NOW());
INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('essay', '作为新时代青年，如何将个人理想融入党和国家事业，实现 人生价值？', '', NULL, '', NOW(), NOW());
