INSERT INTO questions (type, question, answer, options, explanation, created_at, updated_at) VALUES ('essay', '请结合党的二十届四中全会精神，谈谈你对“为什么高质量 发展是全面建设社会主义现代化国家的首要任务”的认识。', '', NULL, '', NOW(), NOW());
